import React from 'react';
import { Link } from 'react-router-dom';

const ROL_ADMIN = 1;

const getRoleName = (id_rol) => {
  switch (id_rol) {
    case 1:
      return "Administrador";
    case 2:
      return "Colaborador";
    default:
      return "Usuario";
  }
};

const Navbar = ({ loggedInUser, onLogout }) => {
  const baseLinks = [
    { label: "NOSOTROS", path: "/historia" },
    { label: "DASHBOARDS", path: "/dashboards" },
    { label: "REVISTA", path: "/revistaPage" },
    { label: "INICIO", path: "/" },
    { label: "EMPRESAS", path: "/empresas" },
    { label: "CONTACTO", path: "/contacto" },

  ];

  let finalLinks = [...baseLinks];
  if (loggedInUser && loggedInUser.id_rol === ROL_ADMIN) {
    finalLinks.push({ label: "ADMIN USUARIOS", path: "/panel-usuarios" });
  }

 const styles = {
    header: {
      width: "100%",
      display: "flex",
      justifyContent: "space-between",
      alignItems: "center",
      padding: "1rem 2.5rem 0.5rem 2.5rem",
      backgroundColor: "#f3efe8",
      position: "relative",
      zIndex: 50,
    },
    iconImg: {
      height: "4.5vh",
      width: "4.5vh",
      cursor: "pointer",
      objectFit: "contain",
      userSelect: "none",
      opacity: 0.8,
    },
    logoSmall: {
      height: "40px",
      objectFit: "contain",
      opacity: 0.7,
      cursor: "default",
    },
    centerContainer: {
      display: "flex",
      alignItems: "center",
      gap: "1rem",
      userSelect: "none",
      cursor: "pointer",
    },
    title: {
      fontFamily: "'Trajan Pro', serif",
      fontSize: "clamp(20px, 4vw, 60px)",
      color: "black",
      whiteSpace: "nowrap",
    },
  };


  return (
    <nav style={styles.navbar}>
      {finalLinks.map((item, index) => (
        <React.Fragment key={index}>
          <Link to={item.path} style={styles.link(item.label === "INICIO")}>
            {item.label}
          </Link>
          {index < finalLinks.length - 1 && (
            <span style={{ color: "#ccc", fontWeight: "100" }}>|</span>
          )}
        </React.Fragment>
      ))}

      {loggedInUser && (
        <div style={styles.userInfo}>
          <span>{loggedInUser.usuario} ({getRoleName(loggedInUser.id_rol)})</span>
          <button style={styles.logoutButton} onClick={onLogout}>
            Cerrar Sesión
          </button>
        </div>
      )}
    </nav>
  );
};

export default Navbar;
